'use client';

import { useEffect } from 'react';
import { useHorizonStore, useFleetStore } from '@/stores';
import {
  mockHorizonItems,
  mockSessions,
  mockConductorScore,
  mockActivityEvents,
} from '@/lib/mockData';

interface DataProviderProps {
  children: React.ReactNode;
}

export function DataProvider({ children }: DataProviderProps) {
  const setItems = useHorizonStore((state) => state.setItems);
  const setSessions = useFleetStore((state) => state.setSessions);
  const setScore = useFleetStore((state) => state.setScore);
  const setRunway = useFleetStore((state) => state.setRunway);
  const setActivityEvents = useFleetStore((state) => state.setActivityEvents);

  useEffect(() => {
    // Initialize stores with mock data
    setItems(mockHorizonItems);
    setSessions(mockSessions);
    setScore(mockConductorScore);
    setRunway(4.2); // 4.2 hours runway
    setActivityEvents(mockActivityEvents);
  }, [setItems, setSessions, setScore, setRunway, setActivityEvents]);

  return <>{children}</>;
}
